import React from "react";
import { useNavigate } from "react-router-dom";
import "../styles/CrisisSupport.css";
import { PhoneCall, MessageCircle, MapPin } from "lucide-react";

function CrisisSupport() {
  const navigate = useNavigate();

  return (
    <div className="crisis-wrapper">
      <div className="crisis-card">

        <h2 className="crisis-title">🛑 Crisis Support</h2>
        <p className="crisis-subtitle">
          You are not alone. Help is available right now.
        </p>

        {/* Call Helpline */}
        <button
          className="crisis-btn danger"
          onClick={() => window.location.href = "tel:988"}
        >
          <PhoneCall size={18} /> Call Helpline
        </button>

        {/* 🔥 THIS WAS MISSING */}
        <button
          className="crisis-btn"
          onClick={() => navigate("/support-chat")}
        >
          <MessageCircle size={18} /> Chat with Support
        </button>

        {/* Find Nearby Help */}
        <button
          className="crisis-btn"
          onClick={() => window.open("https://www.google.com/maps/search/mental+health+support+near+me")}
        >
          <MapPin size={18} /> Find Nearby Help
        </button>

        <div className="breathing-box">
          <h4>🫁 60-Second Breathing</h4>
          <p>Inhale 4 • Hold 4 • Exhale 6</p>
        </div>

        <p className="crisis-footer">
          This moment is hard — but it will pass.  
          You matter more than you know.
        </p>

      </div>
    </div>
  );
}

export default CrisisSupport;
